mapper.insert:
INSERT INTO journal_entries (
    company_id, entry_date, description, 
    total_debit_amount, total_credit_amount, 
    status, confidence_score
) VALUES (
    #{companyId}::uuid, #{entryDate}, #{description},
    #{totalDebitAmount}, #{totalCreditAmount},
    #{status}::journal_entry_status, #{confidenceScore}
)

INSERT INTO journal_entry_details (
    journal_entry_id, line_number, account_code, account_name,
    debit_amount, credit_amount, description
) VALUES (
    #{journalEntryId}, #{lineNumber}, #{accountCode}, #{accountName},
    #{debitAmount}, #{creditAmount}, #{description}
)

mapper.select:
SELECT je.id, je.company_id, je.entry_date, je.description, je.total_debit_amount, je.total_credit_amount, je.status, je.confidence_score, je.posted_at FROM journal_entries je
AND je.company_id = #{companyId}::uuid
AND je.status = #{status}::journal_entry_status
AND (je.description ILIKE '%' || #{search} || '%' OR EXISTS ( SELECT 1 FROM journal_entry_details jed WHERE jed.journal_entry_id = je.id AND jed.account_name ILIKE '%' || #{search} || '%' ))
AND je.entry_date >= #{startDate}
AND je.entry_date <= #{endDate}
ORDER BY je.entry_date DESC, je.id DESC LIMIT #{pageSize} OFFSET #{offset}

SELECT COUNT(*) FROM journal_entries je
AND je.company_id = #{companyId}::uuid
AND je.status = #{status}::journal_entry_status
AND (je.description ILIKE '%' || #{search} || '%' OR EXISTS ( SELECT 1 FROM journal_entry_details jed WHERE jed.journal_entry_id = je.id AND jed.account_name ILIKE '%' || #{search} || '%' ))
AND je.entry_date >= #{startDate}
AND je.entry_date <= #{endDate}

mapper.update:
UPDATE journal_entries SET status = #{status}::journal_entry_status,
posted_at = CURRENT_TIMESTAMP,
updated_at = CURRENT_TIMESTAMP WHERE id = #{journalEntryId}

